  ('locality-6f0ba476-moex-00105', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲畜牧公司於X1年購入幼雞1,000隻，準備未來屠宰出售，每隻幼雞之公允價值減出售成 本為$250。X1年投入飼料成本$80,000，人事成本$63,000。年底若要將幼雞全數售出，每隻 幼雞可賣得$400，相關運費$1,700。試計算X1年財務狀況表中應表達之生物資產金額：', '["$400,000", "$398,300", "$393,000", "$250,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00106', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司於112年7月1日發行面額$1,000,000、利率6%之五年期公司債，每年7月1日付息 一次；發行時市場利率為5%，發行價格為$1,043,760，該公司以有效利率法攤銷公司債之溢 折價。請問112年度甲公司應認列的利息費用為若干？', '["$25,000", "$26,094", "$31,310", "$50,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00107', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司之庫藏股票會計處理採成本法，X1年1月1日無庫藏股。X1年5月1日，以每股$15 之價格買回300,000股之庫藏股票。X1年6月1日，以每股價格$17出售100,000股。X1年 7月1日，以每股價格$13出售150,000股。X1年9月1日，以每股價格$10出售50,000股。 這些庫藏股票交易對X1年底財務報表之影響為：', '["本期淨利減少$350,000", "資本公積減少$200,000", "資本公積減少$550,000", "保留盈餘減少$350,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00108', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司於112年初以$1,200,000購買乙公司普通股60,000股，並分類為透過其他綜合損益按 公允價值衡量證券投資。112年底該投資公允價值為$1,000,000，113年中以公允價值$1,040,000 出售。試問113年甲公司之損益表應列示與該投資有關之本期（損）益為若干？', '["$0", "$40,000", "$(40,000)", "$(80,000)"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00109', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司將收取之利息分類為營業活動現金流量，X1年由營業活動現金流量淨流出$136,500， 其中折舊費用$13,300，應收帳款淨額增加$50,000，應付帳款增加$15,400，預付款項增加 $1,400，長期債券投資折價攤銷$4,500，處分不動產、廠房及設備利得$120,600，試計算甲公 司X1年淨利：', '["$2,300", "$11,300", "$154,700", "$284,300"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00110', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司113年銷貨收入為$1,600,000、銷貨成本為$1,200,000；113年初應收帳款$300,000、應付 帳款$40,000、存貨$136,000；113年底應收帳款$360,000、存貨$144,000、應付帳款$30,000。試 問甲公司當年度（113年度）支付供應商貨款金額為多少？', '["$1,182,000", "$1,198,200", "$1,218,000", "$1,258,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00111', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年9月1日收到顧客之票據一紙，面額$300,000，附息10%，6個月期。甲公 司於X1年12月1日將該票據向銀行貼現，貼現率12%，貼現期間3個月。下列敘述何者 正確？', '["到期值為$330,000", "貼現息為$18,900", "貼現金額為$311,100", "貼現損失為$1,950"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00112', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '下列為甲公司比較財務報表之資訊： X2年 X1年 應收帳款（淨額） $ 200,000 $250,000 存貨 150,000 180,000 資產總額 1,400,000 900,000 流動負債 150,000 100,000 長期負債 300,000 250,000 賒銷淨額 1,680,000 800,000 銷貨成本 800,000 500,000 利息費用 20,000 25,000 所得稅費用 80,000 20,000 淨利 200,000 120,000 下列關於X2年財務比率之敘述何者錯誤？', '["應收帳款週轉率約為7.47次", "負債比率約為32.14%", "存貨週轉率約為1.21次", "資產投資報酬率約為17.39%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00113', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'essay', '甲向乙銀行借款購買A屋，以A屋設定抵押權擔保該筆借款清償，借款
合約書並有逾期未清償須支付違約金之約定。嗣後，甲屆期未清償借款，
乙銀行遂聲請拍賣前開抵押物。甲則抗辯，其與乙銀行間約定之違約金超
過法律規定之利率甚多，乙銀行對於超過部分既無請求權，故乙銀行聲請
拍賣 A 屋並無理由。嗣後，A 屋被丙縱火燒毀滅失。甲旋即主張，乙銀
